mapper.select:
SELECT chat_member_role
FROM chat_member
WHERE chatroom_id = #{chatroomId}
AND member_id = #{memberId}
AND chat_member_status = '참여중'

mapper.delete:
DELETE FROM chat_member
WHERE chatroom_id = #{chatroomId}
AND member_id = #{memberId}

mapper.update:
UPDATE chat_member
SET chat_member_status = '강퇴'
WHERE chatroom_id = #{chatroomId}
  AND member_id = #{memberId}
  AND chat_member_status = '참여중'

mapper.select:
SELECT COUNT(*)
FROM chat_member
WHERE chatroom_id = #{chatroomId}
  AND member_id = #{memberId}
  AND chat_member_status = '강퇴'
